namespace sv_d8a80096bf094796ab52f02503895364.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> Updates);

public record StatusUpdate(DateTimeOffset Timestamp, string Description);

using sv_d8a80096bf094796ab52f02503895364.Client.Services;

namespace sv_d8a80096bf094796ab52f02503895364.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            "TRK-001",
            "In Transit",
            "Chicago, IL",
            new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 23, 8, 0, 0, TimeSpan.Zero), "Package picked up from sender"),
                new(new DateTimeOffset(2026, 5, 24, 14, 30, 0, TimeSpan.Zero), "Arrived at sorting facility – Dallas, TX"),
                new(new DateTimeOffset(2026, 5, 25, 6, 15, 0, TimeSpan.Zero), "Departed sorting facility – en route to Chicago, IL"),
            }),
        ["TRK-002"] = new ShipmentDetails(
            "TRK-002",
            "Delivered",
            "Seattle, WA",
            new DateTimeOffset(2026, 5, 24, 12, 0, 0, TimeSpan.Zero),
            new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 21, 9, 0, 0, TimeSpan.Zero), "Package picked up from sender"),
                new(new DateTimeOffset(2026, 5, 22, 11, 0, 0, TimeSpan.Zero), "In transit – Portland, OR"),
                new(new DateTimeOffset(2026, 5, 23, 16, 45, 0, TimeSpan.Zero), "Out for delivery"),
                new(new DateTimeOffset(2026, 5, 24, 10, 20, 0, TimeSpan.Zero), "Delivered – left at front door"),
            }),
        ["TRK-003"] = new ShipmentDetails(
            "TRK-003",
            "Processing",
            "New York, NY",
            new DateTimeOffset(2026, 5, 30, 18, 0, 0, TimeSpan.Zero),
            new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 25, 10, 0, 0, TimeSpan.Zero), "Label created – awaiting pickup"),
            }),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

using System.Net.Http.Json;

namespace sv_d8a80096bf094796ab52f02503895364.Client.Services;

public class ShipmentHttpService : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentHttpService(HttpClient http)
    {
        _http = http;
    }

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct)
            ?? throw new InvalidOperationException("Received null response from shipment API.");
    }
}

using sv_d8a80096bf094796ab52f02503895364.Client.Services;

namespace sv_d8a80096bf094796ab52f02503895364;

public static class ShipmentsEndpoints
{
    public static void MapShipmentsApi(this WebApplication app)
    {
        app.MapGet("api/shipments/{trackingNumber}", async (
            string trackingNumber,
            IShipmentService shipmentService,
            CancellationToken ct) =>
        {
            try
            {
                var shipment = await shipmentService.GetShipmentAsync(trackingNumber, ct);
                return Results.Ok(shipment);
            }
            catch (KeyNotFoundException)
            {
                return Results.NotFound();
            }
        });
    }
}

