@page "/shipments/{TrackingNumber}"
@using sv_d8a80096bf094796ab52f02503895364.Client.Services
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment details for @TrackingNumber&hellip;</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Status Updates</h3>
    <ul>
        @foreach (var update in _shipment.Updates)
        {
            <li>
                <strong>@update.Timestamp.ToString("g")</strong> &mdash; @update.Description
            </li>
        }
    </ul>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;
    private string? _lastLoadedTrackingNumber;

    protected override async Task OnParametersSetAsync()
    {
        // Only reload if the tracking number actually changed
        if (string.Equals(_lastLoadedTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase)
            && _shipment is not null)
        {
            return;
        }

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        CancelPendingRequest();

        _lastLoadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _errorMessage = null;
        _loading = true;

        var cts = new CancellationTokenSource();
        _cts = cts;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, cts.Token);
        }
        catch (OperationCanceledException)
        {
            // Request was cancelled (navigation or dispose) — do nothing
            return;
        }
        catch (TaskCanceledException)
        {
            Logger.LogWarning("Shipment request for {TrackingNumber} timed out.", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException)
        {
            Logger.LogWarning("Shipment request for {TrackingNumber} timed out.", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (KeyNotFoundException ex)
        {
            Logger.LogWarning(ex, "Shipment {TrackingNumber} not found.", TrackingNumber);
            _errorMessage = $"Shipment '{TrackingNumber}' was not found.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load shipment {TrackingNumber}.", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            // Only update loading state if this CTS is still current
            if (_cts == cts)
            {
                _loading = false;
            }
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    private void CancelPendingRequest()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPendingRequest();
    }
}

